SELECT e.department, SUM(s.sale_amount) AS total_sales
FROM Employees e
JOIN Sales s ON e.employee_id = s.employee_id
WHERE s.sale_amount > 500
GROUP BY e.department
HAVING SUM(s.sale_amount) > 1000;

function processUsers(users) {
  // Remove duplicates
  const uniqueUsers = [];
  for (let i = 0; i < users.length; i++) {
    let isDuplicate = false;
    for (let j = 0; j < uniqueUsers.length; j++) {
      if (users[i].id === uniqueUsers[j].id) {
        isDuplicate = true;
        break;
      }
    }
    if (!isDuplicate) uniqueUsers.push(users[i]);
  }

  // Sort by age
  uniqueUsers.sort(function(a, b) {
    return a.age - b.age;
  });

  // Map to simplified format
  const result = [];
  for (let i = 0; i < uniqueUsers.length; i++) {
    result.push({ name: uniqueUsers[i].name, age: uniqueUsers[i].age });
  }

  return result;
}

